import{_ as d,o as r,c as a,ag as e}from"./chunks/framework.CQYuu_FX.js";const c=JSON.parse('{"title":"店舗設定","description":"","frontmatter":{"title":"店舗設定"},"headers":[],"relativePath":"tenant/16-settings.md","filePath":"tenant/16-settings.md"}'),l={name:"tenant/16-settings.md"};function i(o,t,h,n,s,b){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="_16-店舗設定" tabindex="-1">16. 店舗設定 <a class="header-anchor" href="#_16-店舗設定" aria-label="Permalink to &quot;16. 店舗設定&quot;">​</a></h1><p>店舗設定では、営業日区切り、税率、注文上限、レジ、レシート、プリンタ、テイクアウト、予約ページ、外観カスタマイズなどを管理します。ここで変更した内容は、お客様画面、ハンディ、KDS、POSレジ、テイクアウト、予約に影響します。</p><h2 id="基本設定" tabindex="-1">基本設定 <a class="header-anchor" href="#基本設定" aria-label="Permalink to &quot;基本設定&quot;">​</a></h2><table tabindex="0"><thead><tr><th>項目</th><th>内容</th></tr></thead><tbody><tr><td>営業日区切り時刻</td><td>日報や売上集計の営業日境界</td></tr><tr><td>税率</td><td>会計金額の計算</td></tr><tr><td>1回の注文品数上限</td><td>セルフ注文やテイクアウトの注文しすぎ防止</td></tr><tr><td>1回の注文金額上限</td><td>高額注文や誤操作の防止</td></tr><tr><td>ラストオーダー時刻</td><td>注文受付を止める時刻</td></tr></tbody></table><h2 id="営業時間と営業日" tabindex="-1">営業時間と営業日 <a class="header-anchor" href="#営業時間と営業日" aria-label="Permalink to &quot;営業時間と営業日&quot;">​</a></h2><p>深夜営業がある店舗では、営業日区切り時刻を必ず確認してください。たとえば営業日区切りが <code>05:00</code> の場合、深夜1時の会計は前日営業分として扱われます。</p><p>影響する主な画面:</p><ul><li>売上レポート</li><li>レジ分析</li><li>運営コックピット</li><li>テイクアウト集計</li><li>予約当日表示</li><li>シフトの当日確認</li></ul><p>税率や注文上限を変更した場合は、テスト注文とテスト会計を行い、セルフオーダー、ハンディ、KDS、POSレジで金額が正しく表示されることを確認してください。</p><h2 id="レジ設定" tabindex="-1">レジ設定 <a class="header-anchor" href="#レジ設定" aria-label="Permalink to &quot;レジ設定&quot;">​</a></h2><table tabindex="0"><thead><tr><th>項目</th><th>内容</th></tr></thead><tbody><tr><td>デフォルト開店金額</td><td>レジ開局時の初期現金額</td></tr><tr><td>過不足閾値</td><td>レジ締め時に差額警告を出す目安</td></tr><tr><td>レジ締め予定時刻</td><td>閉店後、締め忘れを判断する基準時刻</td></tr><tr><td>締め忘れ警告 猶予分</td><td>予定時刻から何分後に警告するか</td></tr><tr><td>利用可能な支払方法</td><td>現金、カード、QR決済</td></tr><tr><td>セルフレジ</td><td>お客様のスマホ決済を有効にするか</td></tr></tbody></table><p>カード・QR決済は、店舗が契約している外部端末で決済完了後、POSLAに記録します。POSLA決済（Stripe Connect）を使う場合は、オーナーダッシュボードで決済設定を完了してからセルフレジやテイクアウトオンライン決済を有効にしてください。</p><h2 id="レシート・領収書" tabindex="-1">レシート・領収書 <a class="header-anchor" href="#レシート・領収書" aria-label="Permalink to &quot;レシート・領収書&quot;">​</a></h2><p>レシート設定では、店舗名、住所、電話番号、フッターを設定します。領収書・インボイスの詳細は、管理画面の <strong>領収書設定</strong> タブで登録番号、発行条件、但し書きを確認してください。</p><p>プリンタ設定では、次を設定できます。</p><table tabindex="0"><thead><tr><th>項目</th><th>内容</th></tr></thead><tbody><tr><td>プリンタ種別</td><td>ブラウザ標準、Star mC-Print3、Epson TM-m30、無効</td></tr><tr><td>プリンタIP</td><td>ネットワークプリンタのIPアドレス</td></tr><tr><td>ポート</td><td>通常は80</td></tr><tr><td>用紙幅</td><td>58mm または 80mm</td></tr><tr><td>自動印刷</td><td>注文確定時のキッチン伝票、会計完了時のレシート</td></tr><tr><td>テスト印刷</td><td>現在の設定でテスト印刷</td></tr></tbody></table><p>プリンタ設定後は、レシート、領収書、キッチン伝票をそれぞれテスト印刷してください。文字化け、用紙幅、余白、金額、店舗名を確認します。</p><h2 id="テイクアウト・予約ページ" tabindex="-1">テイクアウト・予約ページ <a class="header-anchor" href="#テイクアウト・予約ページ" aria-label="Permalink to &quot;テイクアウト・予約ページ&quot;">​</a></h2><p>テイクアウトを有効にすると、店舗設定画面にテイクアウト注文ページのURLとQRコードが表示されます。</p><p>テイクアウト設定:</p><table tabindex="0"><thead><tr><th>項目</th><th>内容</th></tr></thead><tbody><tr><td>テイクアウト受付</td><td>お客様向け注文を受け付けるか</td></tr><tr><td>最短準備時間</td><td>注文から最短何分後に受取可能にするか</td></tr><tr><td>時間枠あたり最大注文数</td><td>同じ受取時刻に受けられる注文数</td></tr><tr><td>時間枠あたり最大品数</td><td>同じ受取時刻に受けられる商品数。0は無制限</td></tr><tr><td>混雑時追加待ち時間</td><td>忙しいときに受取可能時刻を遅らせる分数</td></tr><tr><td>受付開始・終了</td><td>お客様が選べる受取時間帯</td></tr><tr><td>ピーク時間帯</td><td>混雑時間帯の個別上限を使う範囲</td></tr><tr><td>ピーク最大注文数・品数</td><td>ピーク時だけ使う上限</td></tr><tr><td>SLA警告</td><td>受取何分前から遅延リスクとして出すか</td></tr><tr><td>オンライン決済</td><td>テイクアウトの事前決済を有効にするか</td></tr></tbody></table><p>予約ページは、予約LP QRとしてURLとQRコードが表示されます。実際のオンライン予約可否、リードタイム、受付日数、予約金、SMS Webhookなどは <strong>予約管理 → 予約設定</strong> で管理します。</p><h2 id="スタッフ・端末管理" tabindex="-1">スタッフ・端末管理 <a class="header-anchor" href="#スタッフ・端末管理" aria-label="Permalink to &quot;スタッフ・端末管理&quot;">​</a></h2><p>スタッフアカウント、端末専用アカウント、表示する業務端末を管理します。退職や端末入替時は不要なアカウントを無効化してください。</p><p>スタッフは1人1アカウント、KDS・レジ・ハンディは端末専用アカウントで運用してください。共有アカウントを使うと、勤怠、監査ログ、スタッフ評価、シフト確認が正しく記録できません。</p><h2 id="外観カスタマイズ" tabindex="-1">外観カスタマイズ <a class="header-anchor" href="#外観カスタマイズ" aria-label="Permalink to &quot;外観カスタマイズ&quot;">​</a></h2><p>外観カスタマイズでは、セルフオーダー画面とテイクアウト画面の表示を店舗らしく調整できます。</p><table tabindex="0"><thead><tr><th>項目</th><th>内容</th></tr></thead><tbody><tr><td>テーマカラー</td><td>お客様画面の強調色</td></tr><tr><td>表示名</td><td>お客様画面のヘッダーに表示する名称</td></tr><tr><td>ロゴ画像</td><td>お客様画面に表示する店舗ロゴ</td></tr></tbody></table><p>ロゴ画像は、URLを直接入力するか、画像アップロードから登録できます。対応形式は PNG、JPEG、WebP、GIF で、5MB以下です。アップロード後は、必ず <strong>設定を保存</strong> を押してください。保存前はアップロードURLが入力欄に入るだけで、店舗設定としては確定していません。</p><p>ロゴやテーマカラーを変更したら、次の画面で見え方を確認してください。</p><ul><li>セルフオーダー画面</li><li>テイクアウト注文画面</li><li>テイクアウト注文詳細画面</li><li>レシートや印刷物に店舗名・ロゴを使う運用がある場合は印刷結果</li></ul><h2 id="外部連携" tabindex="-1">外部連携 <a class="header-anchor" href="#外部連携" aria-label="Permalink to &quot;外部連携&quot;">​</a></h2><p>「オーナーダッシュボード」の <strong>「外部連携」タブ</strong> から、以下のサービスと接続できます。</p><h3 id="line公式アカウント連携" tabindex="-1">LINE公式アカウント連携 <a class="header-anchor" href="#line公式アカウント連携" aria-label="Permalink to &quot;LINE公式アカウント連携&quot;">​</a></h3><ul><li><strong>用途</strong>: 予約確定、24時間前/2時間前リマインド、テイクアウト準備完了の通知（LINE v1）を自動送信します。</li><li><strong>未提供機能</strong>: メッセージの自由配信UI、リッチメニューの管理、LIFF 連携などは LINE v2 として計画中のバックログであり、現在は利用できません。</li><li><strong>設定</strong>: LINE Developers で発行したトークンを登録します。</li></ul><h3 id="スマレジ連携" tabindex="-1">スマレジ連携 <a class="header-anchor" href="#スマレジ連携" aria-label="Permalink to &quot;スマレジ連携&quot;">​</a></h3><ul><li><strong>用途</strong>: POSLA の注文データを自動的にスマレジへ送信し、売上を統合します。</li><li><strong>連携手順</strong>: <ol><li>「スマレジ連携」画面から <strong>OAuth 認証</strong> を行い、スマレジアカウントにログインして接続を承認します。</li><li>連携成功後、<strong>店舗マッピング</strong> 画面で POSLA の各店舗とスマレジの各店舗を紐付けます。</li><li>必要に応じて「メニューインポート」を実行し、スマレジ側の商品情報を POSLA へ取り込みます。</li></ol></li></ul><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>設定が保存できない</td><td>必須項目と入力形式を確認してください。</td></tr><tr><td>税率が違う</td><td>店舗設定と商品ごとの税区分を確認してください。</td></tr><tr><td>QRコードが表示されない</td><td>対象機能が有効になっているか確認してください。</td></tr><tr><td>レシート内容が違う</td><td>店舗情報、領収書設定、プリンタ設定を確認してください。</td></tr><tr><td>テイクアウト枠が出ない</td><td>受付時間、最短準備時間、枠上限、ピーク上限、オンライン決済を確認してください。</td></tr><tr><td>ロゴが反映されない</td><td>画像アップロード後に「設定を保存」したか、画像形式とサイズを確認してください。</td></tr></tbody></table>',39)])])}const u=d(l,[["render",i]]);export{c as __pageData,u as default};
